const s = global.get("mesSnapshot") || { values: {}, updatedAt: null, count: 0 };
const values = s.values || {};

function n(m, p, node, d = 0) {
    const candidates = [`${m}|${p}|${node}`, `${m}|none|${node}`, `${m}|${p || "none"}|${node}`];
    for (const k of candidates) {
        if (values[k] !== undefined && values[k] !== null && values[k] !== "") {
            const num = Number(values[k]);
            if (Number.isFinite(num)) return num;
        }
    }
    return d;
}

function b(m, p, node) { return n(m, p, node, 0) === 1 ? 1 : 0; }
function round(x, d = 2) { return Math.round((Number(x) || 0) * Math.pow(10, d)) / Math.pow(10, d); }
function clamp(x, min, max) { return Math.max(min, Math.min(max, x)); }

const pe = n("powergrid", "PLC2", "PE.Power");
const fs = n("powergrid", "PLC2", "FS.Power");
const gs = n("powergrid", "PLC2", "GS.Power");
const productionTotal = pe + fs + gs;

const tap = n("powergrid", "PLC2", "TAP", productionTotal);
const factoryDemand = n("powergrid", "PLC2", "MES.FactoryDemand");
const homesDemand = n("powergrid", "PLC2", "MES.HomesDemand");
const railwayDemand = n("powergrid", "PLC2", "MES.RailwayDemand");
const losses = n("powergrid", "PLC2", "MES.Losses");

const tcpComputed = factoryDemand + homesDemand + railwayDemand + losses;
const tcp = tcpComputed > 0 ? tcpComputed : n("powergrid", "PLC2", "TCP", 0);
const delta = tap - tcp;

const installationActive = b("factory", "none", "EtatInstallation");
const plantOperational = b("factory", "none", "EtatUsine") || b("factory", "none", "MES.FactoryRunning");
const cycleActive = b("factory", "none", "MES.CycleActive") || b("factory", "none", "CycleActif");
const cycleFinished = b("factory", "none", "MES.CycleDone") || b("factory", "none", "CycleTermine");
const recyclingActive = b("factory", "none", "MES.RecycleActive") || b("factory", "none", "RecyclageActif");

const step1 = b("railauto", "none", "Etape1.Terminee");
const step2 = b("railauto", "none", "Etape2.Terminee");
const step3 = b("railauto", "none", "Etape3.Terminee");
const step4 = b("railauto", "none", "Etape4.Terminee");

const completedSteps = step1 + step2 + step3 + step4;
const progressPct = completedSteps * 25;

const energyScore = tap > 0 ? clamp(Math.round((1 - Math.abs(delta) / Math.max(tap, 1)) * 100), 0, 100) : 0;
const factoryScore = clamp(Math.round(installationActive * 30 + plantOperational * 30 + cycleActive * 20 + (cycleFinished > 0 ? 10 : 0) + (1 - recyclingActive) * 10), 0, 100);
const railScore = clamp(progressPct, 0, 100);
const globalScore = Math.round((energyScore + factoryScore + railScore) / 3);

msg.headers = { "Content-Type": "application/json" };
msg.payload = {
    powergrid: { tap: round(tap), tcp: round(tcp), delta: round(delta), totalProduction: round(productionTotal || tap) },
    factory: { installationActive, cycleActive, cycleFinished: cycleFinished > 0 ? 1 : 0 },
    railauto: { completedSteps, progressPct },
    scores: { energy: energyScore, factory: factoryScore, rail: railScore, global: globalScore },
    alerts: { deficit: delta < 0 ? 1 : 0, factoryBlocked: installationActive ? 0 : 1, railBlocked: progressPct < 25 ? 1 : 0 },
    status: delta < 0 ? "deficit" : globalScore >= 70 ? "stable" : "degraded",
    generatedAt: new Date().toISOString(),
    sourceUpdatedAt: s.updatedAt,
    pointCount: s.count || 0
};
return msg;

