    losses: round(losses),
    reserve: round(delta),
    servedStatus: [
        { name: "Factory", served: factoryServed, demand: round(factoryDemand) },
        { name: "Homes", served: homesServed, demand: round(homesDemand) },
        { name: "Railway", served: railwayServed, demand: round(railwayDemand) }
    ],
    anomalySummary,
    generatedAt: new Date().toISOString(),
    sourceUpdatedAt: s.updatedAt,
    pointCount: s.count || 0
